public class DocData { private String name ; private String body ; private String title ; private Date date ; private Properties props ; public DocData ( String name , String body , String title , Properties props , Date date ) { this . name = name ; this . body = body ; this . title = title ; this . date = date ; this . props = props ; } public String getName ( ) { return name ; } public void setName ( String name ) { this . name = name ; } public Properties getProps ( ) { return props ; } public void setProps ( Properties props ) { this . props = props ; } public String getBody ( ) { return body ; } public void setBody ( String body ) { this . body = body ; } public String getTitle ( ) { return title ; } public void setTitle ( String title ) { this . title = title ; } public Date getDate ( ) { return date ; } public void setDate ( Date date ) { this . date = date ; } }